parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const urgencyMap = { high: '🔴 גבוהה', normal: '🟡 רגילה', low: '🟢 נמוכה' };
const now = new Date();
const israelTime = new Date(now.getTime() + 3 * 60 * 60 * 1000);
const pad = n => String(n).padStart(2, '0');
const dateStr = pad(israelTime.getUTCDate()) + '/' + pad(israelTime.getUTCMonth()+1) + '/' + israelTime.getUTCFullYear();
const timeStr = pad(israelTime.getUTCHours()) + ':' + pad(israelTime.getUTCMinutes());
return [{json: {
  id: body.id,
  customer_name: body.customer_name || 'לא ידוע',
  address: body.address || 'לא צוין',
  description: body.description || 'לא צוין',
  urgency: body.urgency || 'normal',
  urgency_label: urgencyMap[body.urgency] || urgencyMap.normal,
  customer_phone: body.customer_phone || '',
  attachments_count: body.attachments_count || 0,
  is_office_open: body.is_office_open !== false,
  timestamp: dateStr + ' ' + timeStr,
}}];

